// Minimal MSAL Browser 2.26.0 Stub for OneDrive integration
// This stub provides the core PublicClientApplication interface when the real MSAL library
// cannot be loaded from CDN due to network restrictions.

(function() {
  'use strict';

  // AuthenticationResult interface
  function AuthenticationResult(accessToken, expiresOn) {
    this.accessToken = accessToken;
    this.expiresOn = expiresOn;
    this.account = null;
  }

  // Account interface
  function Account(homeAccountId, environment, tenantId, localAccountId, username, name) {
    this.homeAccountId = homeAccountId;
    this.environment = environment;
    this.tenantId = tenantId;
    this.localAccountId = localAccountId;
    this.username = username;
    this.name = name;
  }

  // PublicClientApplication - main MSAL class
  function PublicClientApplication(config) {
    this.config = config || {};
    this.accounts = [];
    this.tokenCache = {};
    this.accessToken = null;
    this.refreshToken = null;
    this.expiresOn = null;
  }

  PublicClientApplication.prototype.loginPopup = function(request) {
    var self = this;
    return new Promise(function(resolve, reject) {
      // Simulate OAuth flow
      var width = 500;
      var height = 600;
      var left = (screen.width - width) / 2;
      var top = (screen.height - height) / 2;

      var popup = window.open(
        'about:blank',
        'mslogin',
        'width=' + width + ',height=' + height + ',left=' + left + ',top=' + top
      );

      if (!popup) {
        reject(new Error('Popup blocked. Please enable popups for this site.'));
        return;
      }

      // Simulate successful login with mock tokens
      setTimeout(function() {
        // Generate mock tokens
        var mockAccessToken = 'mock_access_token_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
        var mockRefreshToken = 'mock_refresh_token_' + Math.random().toString(36).substr(2, 9);
        var expiresOn = new Date(Date.now() + 3600000); // 1 hour from now

        self.accessToken = mockAccessToken;
        self.refreshToken = mockRefreshToken;
        self.expiresOn = expiresOn;

        // Create mock account
        var mockAccount = new Account(
          'local-' + Date.now(),
          'login.microsoftonline.com',
          'common',
          'local-' + Date.now(),
          'user@outlook.com',
          'Mock User'
        );

        self.accounts.push(mockAccount);
        self.tokenCache[mockAccessToken] = {
          accessToken: mockAccessToken,
          expiresOn: expiresOn,
          refreshToken: mockRefreshToken,
          account: mockAccount
        };

        if (popup) {
          try {
            popup.close();
          } catch (e) {
            // Ignore popup close errors
          }
        }

        resolve({
          accessToken: mockAccessToken,
          expiresOn: expiresOn,
          account: mockAccount
        });
      }, 1500); // Simulate network delay
    });
  };

  PublicClientApplication.prototype.acquireTokenSilent = function(request) {
    var self = this;
    return new Promise(function(resolve, reject) {
      if (self.accessToken && self.expiresOn && new Date() < self.expiresOn) {
        // Token still valid
        resolve({
          accessToken: self.accessToken,
          expiresOn: self.expiresOn
        });
      } else if (self.refreshToken) {
        // Refresh token
        setTimeout(function() {
          var newAccessToken = 'mock_access_token_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
          var newExpiresOn = new Date(Date.now() + 3600000);

          self.accessToken = newAccessToken;
          self.expiresOn = newExpiresOn;

          resolve({
            accessToken: newAccessToken,
            expiresOn: newExpiresOn
          });
        }, 500);
      } else {
        reject(new Error('No token available. User must sign in first.'));
      }
    });
  };

  PublicClientApplication.prototype.logout = function(logoutRequest) {
    return new Promise(function(resolve) {
      this.accessToken = null;
      this.refreshToken = null;
      this.expiresOn = null;
      this.accounts = [];
      this.tokenCache = {};
      resolve();
    }.bind(this));
  };

  PublicClientApplication.prototype.getAllAccounts = function() {
    return this.accounts;
  };

  PublicClientApplication.prototype.getAccountByUsername = function(username) {
    for (var i = 0; i < this.accounts.length; i++) {
      if (this.accounts[i].username === username) {
        return this.accounts[i];
      }
    }
    return null;
  };

  PublicClientApplication.prototype.initialize = function() {
    var self = this;
    return new Promise(function(resolve) {
      // Synchronous initialization for stub
      resolve();
    });
  };

  PublicClientApplication.prototype.acquireTokenPopup = function(request) {
    var self = this;
    return new Promise(function(resolve, reject) {
      // Simulate popup login with mock tokens (no actual popup needed)
      console.debug('[MSAL Stub] acquireTokenPopup called, simulating OAuth flow');

      // Simulate successful login with mock tokens
      setTimeout(function() {
        var mockAccessToken = 'mock_access_token_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
        var mockRefreshToken = 'mock_refresh_token_' + Math.random().toString(36).substr(2, 9);
        var expiresOn = new Date(Date.now() + 3600000); // 1 hour from now

        self.accessToken = mockAccessToken;
        self.refreshToken = mockRefreshToken;
        self.expiresOn = expiresOn;

        // Create mock account if not already created
        if (self.accounts.length === 0) {
          var mockAccount = new Account(
            'local-' + Date.now(),
            'login.microsoftonline.com',
            'common',
            'local-' + Date.now(),
            'user@outlook.com',
            'Mock User'
          );
          self.accounts.push(mockAccount);
        }

        console.debug('[MSAL Stub] Mock login successful, returning token');
        resolve({
          accessToken: mockAccessToken,
          expiresOn: expiresOn,
          account: self.accounts[0]
        });
      }, 1500); // Simulate network delay
    });
  };

  PublicClientApplication.prototype.logoutPopup = function(request) {
    var self = this;
    return new Promise(function(resolve) {
      self.accessToken = null;
      self.refreshToken = null;
      self.expiresOn = null;
      self.accounts = [];
      self.tokenCache = {};
      console.debug('[MSAL Stub] Logout complete');
      resolve();
    });
  };

  // LogLevel enum
  var LogLevel = {
    Verbose: 0,
    Info: 1,
    Warning: 2,
    Error: 3
  };

  // Export to window.msal
  window.msal = window.msal || {};
  window.msal.PublicClientApplication = PublicClientApplication;
  window.msal.LogLevel = LogLevel;

  console.log('[MSAL Stub] Minimal MSAL stub loaded. Using mock authentication.');
})();
